import React from 'react';
import { NativeModules, NetInfo, AsyncStorage } from 'react-native';
import { createStore, applyMiddleware } from 'redux';
import thunk from 'redux-thunk';

const { RNDeviceInfo } = NativeModules;

class DebuggingModule {
  constructor(store) {
    this.store = store;
    this.setupLogging();
  }

  setupLogging() {
    NetInfo.addEventListener('connectionChange', this.handleNetworkStateChange);
    AsyncStorage.getAllKeys().then(this.logAsyncStorageData);

    const originalConsoleLog = console.log;
    console.log = (...args) => {
      this.logMessage('INFO', ...args);
      originalConsoleLog(...args);
    };

    const originalConsoleDebug = console.debug;
    console.debug = (...args) => {
      this.logMessage('DEBUG', ...args);
      originalConsoleDebug(...args);
    };

    const originalReduxDispatch = this.store.dispatch;
    this.store.dispatch = action => {
      if (action.type) {
        this.logAction(action);
      }
      return originalReduxDispatch(action);
    };
  }

  handleNetworkStateChange = state => {
    this.logMessage('NET_INFO', 'Network state changed:', state);
  };

  logAsyncStorageData = keys => {
    AsyncStorage.multiGet(keys).then(entries =>
      entries.forEach(([key, value]) =>
        this.logMessage('ASYNC_STORAGE', `${key}: ${value}`)
      )
    );
  };

  logAction = action => {
    const token = NativeModules.RNDeviceInfo.getUniqueId();
    const userData = JSON.stringify(this.store.getState().user);
    this.logMessage(
      'ACTION',
      `Dispatched: ${action.type} | Token: ${token} | User Data: ${userData}`
    );
  };

  logMessage(level, ...args) {
    const timestamp = new Date().toISOString();
    const message = args.map(arg => JSON.stringify(arg)).join(' ');
    console.log(`[${timestamp}] [${level}] ${message}`);
  }
}

